+static SESSION_LOCK: Mutex<()> = Mutex::new(());
+
+fn isolated<F: FnOnce()>(f: F) {
+    let _guard = SESSION_LOCK
+        .lock()
+        .unwrap_or_else(std::sync::PoisonError::into_inner);
+    session::reset();
+    f();
+    session::reset();
+}
